// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        // 초기화
        scwin.f_defaultValue();
        //ed_odrNo.setValue("IDJ1501010001");
        //ed_odrNo.setValue("IB42602120001");

    }, { "delay": 0 }); //delay 주면 버튼 활성화 꼬임
};

//-------------------------------------------------------------------------
// 초기값 설정
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function () {
    // 물류점소 운영부서 조회조건 SET
    scwin.f_dsLobranQueryConditionHeader();

    // KeyData 비활성화
    $c.gus.cfDisableKeyData();

    // 그리드 행추가 / 삭제 /취소 버튼 비활성화
    $c.gus.cfDisableAllBtn();

    // 로그인 사용자 물류점소 - 운송부서 조회
    if (scwin.wrkLobranCd == "4A5") {
        dma_lobranQueryCondition.set("deptmentCd", 5);
    } else {
        dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT); // 운송부서
    }

    let e = await $c.sbm.execute(sbm_retrieveLobranTrans);

    //-------------------------------------------------------------------------
    // 사용자 물류점소 운송부서 정보 조회 submitdone
    //-------------------------------------------------------------------------
    //scwin.sbm_retrieveLobranTrans_submitdone
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_lobran.getRowCount() > 0) {

        // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
        if (scwin.userId == "040239") {
            scwin.internalSellLodeptCd = "4A5";
            scwin.internalSellLodeptNm = "인천제강운송";
        } else {
            scwin.internalSellLodeptCd = ds_lobran.getCellData(0, "lobranCd");  // 운송부서코드
            scwin.internalSellLodeptNm = ds_lobran.getCellData(0, "lobranNm");  // 운송부서명
        }
    }
    ///////////////////

    // gr_odrCommWrkPath.setReadOnly("grid", false);
    scwin.gr_odrCommWrkPath_setReadOnly(false);
    scwin.gr_odrCommWrkPath_editable = true;
    scwin.hid_chkUseFilter = true;


    // 오더 확정 버튼/ 작업일시배분 조회및 수정 버튼 비활성화

    $c.gus.cfDisableObjects([btn_confirmOrder, btn_orderWrkStepDetail, btn_dcSc]);

    ed_odrNo.focus();
};

//-------------------------------------------------------------------------
// 물류점소 운영부서 조회조건 SET
