//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    let ret = await $c.gus.cfValidate([ed_odrNo]);
    if (ret) {
        var odrNo = ed_odrNo.getValue().replace(/\s*$/, '');

        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();
        $c.gus.cfEnableBtnOnly([btn_save]);

        ds_order.setJSON([]);
        ds_odrCommWrkPath.setJSON([]);
        ds_ctrtWrkPath.setJSON([]);
        ds_odrWrkPathStep.setJSON([]);
        ds_ctrtWrkPathStep.setJSON([]);

        // 그리드 총건수 초기화
        tbx_totalRows.setValue("0");
        tbx_totalRows2.setValue("0");

        $c.gus.cfDisableObjects([btn_confirmOrder, btn_orderWrkStepDetail, btn_dcSc]);

        ds_odrWrkPathStepDetail.setJSON([]);
        ds_odrWrkPathStepDetailTemp.setJSON([]);

        // 작업단계 그리드 : 작업장구분 콤보박스 조회
        dma_wrkPlClsCd.set("grpCd", "LO121");
        await $c.sbm.execute(sbm_getWrkPlClsCd);
        ds_wrkPlClsCd.insertRow(0);
        ds_wrkPlClsCd.setCellData(0, "cd", " ");
        ds_wrkPlClsCd.setCellData(0, "cdNm", "→");

        // 작업단계 그리드 : 작업단계 콤보박스 조회
        await $c.sbm.execute(sbm_getLkStepNo);

        ds_order.setJSON([]);
        ds_odrCommWrkPath.setJSON([]);
        ds_ctrtWrkPath.setJSON([]);

        let result = await $c.sbm.execute(sbm_retrieve);

        scwin.sbm_retrieve_submitdone(result);
    }

};

