scwin.f_RetrieveWorkStep = function () {
    if (dma_searchWrkStep.get("ctrtWrkPathSeq") == 0) {
        console.log("여기왔나요..?")
        return;
    }

    // 선택된 작업경로별 작업단계 조회
    $c.sbm.execute(sbm_searchWorkStep); //TOBE : onrowpositionchange 호출되는 서브미션은 await 처리가 안되서 해당 서브미션만 sync 처리함

    // 작업단계 그리드에 설정
    scwin.f_setWorkPathStepDetail();
}

