//-------------------------------------------------------------------------
// 선택된 DATASET에 ROW 복사 ( 대상 DataSet, 원본 Row, 대상 Row )
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function (dataObject, sourceRow, targetRow) {
    var v_odrWrkStpSeq = dataObject.getCellData(sourceRow, "odrWrkStpSeq");
    var v_tempSeq = parseInt(v_odrWrkStpSeq / 10) * 10;
    var colId = "";

    for (var i = 0; i < dataObject.getTotalCol(); i++) {
        colId = dataObject.getColumnID(i);
        if (colId == "odrWrkStpSeq") {
            dataObject.setCellData(targetRow, colId, parseInt(dataObject.getCellData(sourceRow, colId)) + 1);
        } else if (colId == "wrkPlClsCd" || colId == "wrkStpCd"
            || colId == "dptWrkPlCd" || colId == "dptWrkPlNm"
            || colId == "arvWrkPlCd" || colId == "arvWrkPlNm"
            || colId == "wrkLobranCd" || colId == "wrkLobranNm"
            || colId == "wrkStDt" || colId == "wrkStHh"
            || colId == "wrkEndDt" || colId == "wrkEndHh"
            || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm"
            || colId == "bizDomCd" || colId == "completeYn") {
        } else if (colId == "selpchItemCd") {
            dataObject.setCellData(targetRow, colId, SdConstants.SELPCH_ITEM_CD_NOSELL);
        } else if (colId == "selpchItemNm") {
            dataObject.setCellData(targetRow, colId, "무매출");
        } else {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        }
    }

    scwin.f_refreshOdrWrkStpSeq(dataObject, v_tempSeq);
};

//-------------------------------------------------------------------------
// 선택된 DATASET에 오더 작업단계 추가 가능 확인
//-------------------------------------------------------------------------
scwin.f_checkOdrWrkStpSeq = function (dataObject, v_tempSeq) {
    for (var j = 0; j < dataObject.getRowCount(); j++) {
        v_compSeq = dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq;

        if ((parseInt(dataObject.getCellData(j, "odrWrkStpSeq") / 10) * 10) == (v_tempSeq && v_compSeq >= 9)) {
            return false;
        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 선택된 DATASET에 오더 작업단계순번 재정의
//-------------------------------------------------------------------------
scwin.f_refreshOdrWrkStpSeq = function (dataObject, v_tempSeq) {
    // 오더작업단계순번 재정의
    for (var j = 0; j < dataObject.getRowCount(); j++) {
        v_compSeq = dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq;

        if (dataObject.getCellData(j, "odrWrkStpSeq") > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
            dataObject.setCellData(j, "odrWrkStpSeq", parseInt(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
        }
    }
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    $c.gus.cfDisableBtnOnly([btn_update]);
    $c.gus.cfEnableBtnOnly([btn_save]);

    // gr_odrCommWrkPath.setReadOnly("grid", false);
    // gr_odrWrkPathStpDetail.setReadOnly("grid", false);
    scwin.gr_odrCommWrkPath_setReadOnly(false);
    scwin.gr_odrWrkPathStpDetail_setReadOnly(false);
    scwin.gr_odrCommWrkPath_editable = true;
    scwin.gr_odrWrkPathStpDetail_editable = true;

    if (ds_odrWrkPathStep.getRowCount() > 0) {
        gr_odrWrkPathStpDetail.setReadOnly("column", "selpchItemNm", true); // 매출입항목

        //$c.gus.cfDisableBtnOnly([btn_insertRow, btn_deleteRow, btn_undoMark]);
    }

    gr_odrWrkPathStpDetail.setFocusedCell(0, "dptWrkPlNm", true); //edit : true

    // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
    // 실적 발생시 수정할 수 없다.
    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    var odrCommWrkPathRow = ds_odrCommWrkPath.getRowPosition();
    if (parseInt(odrCommWrkPathRow) >= 0 && btn_update.getDisabled()) {
        if (scwin.f_chkResultsConfirmationCommodity(odrCommWrkPathRow)) {
            // gr_odrCommWrkPath.setReadOnly("grid", true);
            // gr_odrWrkPathStpDetail.setReadOnly("grid", true);
            scwin.gr_odrCommWrkPath_setReadOnly(true);
            scwin.gr_odrWrkPathStpDetail_setReadOnly(true);
            scwin.gr_odrCommWrkPath_editable = false;
            scwin.gr_odrWrkPathStpDetail_editable = false;

            //$c.gus.cfDisableBtnOnly([btn_insertRow, btn_deleteRow, btn_undoMark]);
        } else {
            // gr_odrCommWrkPath.setReadOnly("grid", false);
            // gr_odrWrkPathStpDetail.setReadOnly("grid", false);
            scwin.gr_odrCommWrkPath_setReadOnly(false);
            scwin.gr_odrWrkPathStpDetail_setReadOnly(false);
            scwin.gr_odrCommWrkPath_editable = true;
            scwin.gr_odrWrkPathStpDetail_editable = true;

            // $c.gus.cfEnableBtnOnly([btn_insertRow, btn_deleteRow, btn_undoMark]);
        }
    }

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(ds_odrWrkPathStepDetail.getRowPosition());
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    // 품명별 작업경로를 선택하지 않은 경우 : 첫번째 품명의 작업경로는 반드시 선택되어야 한다.
    if (ds_odrCommWrkPath.getCellData(0, "ctrtWrkPathSeq") <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업경로")); //작업경로을(를) 선택하십시오.
        gr_odrCommWrkPath.setFocusedCell(0, "ctrtWrkPathSeq", true); //edit : true
        return;
    }

    // 작업단계 정보 설정확인
    for (var i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        // 작업구분이 지정되지 않은 경우(운송) 이전 단계의 작업장을 출발작업장으로, 다음 단계의 작업장을 도착작업장으로 설정한다.
        // 작업점소가 설정되지 않은 경우 작업점소는 이전 작업단계의 작업 점소를 설정한다.
        if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() == "" && i > 0) {
            // 작업장
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")))
                ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd")))
                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlNm")))
                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm"));
        }
    }

    let validArray = [
        { id: "odrNo", name: "오더번호", mandatory: true },
        { id: "commSeq", name: "품명순번", mandatory: true },
        { id: "odrWrkPathSeq", name: "오더작업경로", mandatory: true },
        { id: "ctrtWrkPathSeq", name: "계약작업경로", mandatory: true },
        { id: "wrkStpCd", name: "작업단계", mandatory: true }
    ];

    // 현재 품명의 작업단계 정보의 Vaildation 을 검사한다.
    let ret = await $c.gus.cfValidateGrid(gr_odrWrkPathStpDetail, null, null, validArray, "작업단계");
    //if (!$c.gus.cfValidate([gr_odrWrkPathStpDetail])) {
    if (!ret) {
        return;
    }

    // 필수 입력 확인
    for (var idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim()) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "dptWrkPlCd").trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장"));
            gr_odrWrkPathStpDetail.setFocusedCell(idx, "dptWrkPlNm", true); //edit : true
            return false;
        }

        // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
        if (ds_odrWrkPathStepDetail.getCellData(idx, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            // 작업점소 확인
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업점소"));
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "wrkLobranNm", true); //edit : true
                return false;
            }

            //매출귀속부서 확인
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("매출귀속부서"));
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "internalSellLodeptNm", true); //edit : true
                return false;
            }
        }
    }

    ds_odrCommWrkPath.setRowPosition(0);

    // 첫번째 품명의 작업단계 정보의 Vaildation 을 검사한다. 
    // if (!$c.gus.cfValidate([gr_odrWrkPathStpDetail])) {  //TOBE : 위에 있는데 이중으로 실행되서 주석처리
    //     return;    // }


    scwin.hid_chkUseFilter = false;
    scwin.ds_odrWrkPathStepDetail_OnFilter();

    var v_wrkPathRows = ds_odrCommWrkPath.getRowCount();
    var v_wrkPathStepRows = ds_odrWrkPathStepDetail.getRowCount();

    // 첫번째 작업단계의 정보를 저장한다.
    var v_odrNo = ds_odrCommWrkPath.getCellData(0, "odrNo");
    var v_commSeq = ds_odrCommWrkPath.getCellData(0, "commSeq");

    // 첫번째 작업 경로 중 사용하지 않는 작업단계를 삭제한다.
    var i = 0;

    for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
        // 삭제 대상 작업단계를 삭제한다.
        if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo")
            && ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq")
            && ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") != ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")
            && ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {

            ds_odrWrkPathStepDetail.removeRow(j);
            j--;
        }

        // 실적이 발생한 작업단계를 제외
        if (!$c.gus.cfIsNull(ds_odrCommWrkPath.getCellData(i, "wrkRsltsNo"))
            && ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo")
            && ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq")
            && ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") == ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")
            && ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {

            ds_odrWrkPathStepDetail.removeRow(j);
            j--;
        }

    }

    // 작업경로/작업단계가 설정되지 않은 품명의 경우 첫번째 작업경로/작업단계를 자동 설정한다.
    for (var i = 0; i < v_wrkPathRows; i++) {

        // 첫번째 작업 경로 중 사용하지 않는 작업단계를 삭제한다.
        if (i == 0) {

            for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {

                // 삭제 대상 작업단계를 삭제한다.
                if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo")
                    && ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq")
                    && ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") != ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")
                    && ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {

                    ds_odrWrkPathStepDetail.removeRow(j);
                    j--;
                }
            }

        }

        if (ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq") <= 0 && i > 1) {
            ds_odrCommWrkPath.setCellData(i, "ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(0, "ctrtWrkPathSeq"));

            // 작업경로별 사용하지 않는 작업단계를 삭제한다.
            for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {

                // 삭제 대상 작업단계를 삭제한다.
                if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo")
                    && ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq")
                    && ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") == ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")
                    && ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {

                    ds_odrWrkPathStepDetail.removeRow(j);
                    j--;
                } else if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo")
                    && ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq")
                    && ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") != ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")
                    && ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {

                    ds_odrWrkPathStepDetail.removeRow(j);
                    j--;
                }
            }

            // 첫번째 품명의 작업 단계를 작업 경로가 지정되지 않은 작업단계에 설정한다.
            // 작업단계 정보 설정확인
            var newRow = "";
            for (var j = 0; j < v_wrkPathStepRows; j++) {
                if (ds_odrWrkPathStepDetail.getRowStatus(j) != "D" // getRowStatus : 2 (DELETE) 가 아닌경우
                    && v_odrNo == ds_odrWrkPathStepDetail.getCellData(j, "odrNo")
                    && v_commSeq == ds_odrWrkPathStepDetail.getCellData(j, "commSeq")) {

                    newRow = ds_odrWrkPathStepDetail.insertRow();
                    ds_odrWrkPathStepDetail.setRowPosition(newRow);

                    for (var k = 0; k < ds_odrWrkPathStepDetail.getTotalCol(); k++) {
                        switch (ds_odrWrkPathStepDetail.getColumnID(k)) {
                            case "commSeq":
                                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), ds_odrWrkPathStepDetail.getColumnID(k),
                                    ds_odrCommWrkPath.getCellData(i, "commSeq"));
                                break;
                            case "odrWrkPathSeq":
                                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), ds_odrWrkPathStepDetail.getColumnID(k),
                                    ds_odrCommWrkPath.getCellData(i, "odrWrkPathSeq"));
                                break;
                            case "ctrtWrkPathSeq":
                                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), ds_odrWrkPathStepDetail.getColumnID(k),
                                    ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq"));
                                break;
                            default:
                                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), ds_odrWrkPathStepDetail.getColumnID(k),
                                    ds_odrWrkPathStepDetail.getCellData(j, ds_odrWrkPathStepDetail.getColumnID(k)));
                                break;
                        }
                    }
                }
            }
        }
    }

    // 작업장구분이 운송인 경우 출발작업장, 도착작업장 정보를 자동 설정한다.
    for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {

        if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == "") {
            if (j > 0 && j < ds_odrWrkPathStepDetail.getRowCount()) {
                // 작업점소
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranNm"));

                // 출발 작업장
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));

                // 도착작업장
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));

                // 매출귀속부서
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL) {
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.매출귀속부서(j + 1, "internalSellLodeptCd").tirm()))
                        ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptCd"));
                }

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL) {
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm").tirm()))
                        ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm"));
                }
            } else if (j == 0) {
                // 작업점소
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkLobranCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkLobranNm"));

                // 도착작업장
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));

                // 매출귀속부서
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm")))
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm"));
            } else {
                // 작업점소
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranNm"));

                // 출발 작업장
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));

                // 매출귀속부서
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptNm")))
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptNm"));
            }
        }
    }

    // TOBE : 실제 실행되는 문장이 없어서 주석 처리함 
    //dptWrkPlCd arvWrkPlCd dptWrkPlCd arvWrkPlCd 작업경로의 출도착작업장 과 작업단계의 작업장을 일치시켜야 함.
    // var chk_gun = "";
    // for (var i = 0; i < ds_odrCommWrkPath.getRowCount(); i++) {
    //     for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {           
    //         if (ds_odrCommWrkPath.getCellData(i, "odrNo") == ds_odrWrkPathStepDetail.getCellData(j, "odrNo")
    //             && ds_odrCommWrkPath.getCellData(i, "commSeq") == ds_odrWrkPathStepDetail.getCellData(j, "commSeq")) {              

    //             if (ds_odrCommWrkPath.getCellData(i, "dptWrkPlCd") == ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd")
    //                 || ds_odrCommWrkPath.getCellData(i, "dptWrkPlCd") == ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd")
    //                 || ds_odrCommWrkPath.getCellData(i, "arvWrkPlCd") == ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd")
    //                 || ds_odrCommWrkPath.getCellData(i, "arvWrkPlCd") == ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd")) {

    //             } else {
    //                 //chk_gun = "1";
    //             }
    //         }
    //     }
    // }

    scwin.hid_chkUseFilter = true;
    scwin.ds_odrWrkPathStepDetail_OnFilter();

    // 필수 입력사항을 체크
    let chk = await scwin.f_validChk()
    if (chk) {
        // 선택되지 않은 작업단계정보 삭제
        scwin.f_chkOdrWrkPathStep();
        let confirm = await $c.win.confirm(MSG_CM_CRM_001);
        if (confirm) {
            // 작업경로 , 작업단계 정보 저장
            $c.sbm.execute(sbm_save);
        }
    }
}

//-------------------------------------------------------------------------
// 저장전 validation check
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    //오더품목 필수 입력사항을 체크
    let ret = await $c.gus.cfValidate([gr_odrCommWrkPath])
    if (!ret) return false;

    ret = await $c.gus.cfValidate([gr_odrWrkPathStpDetail])
    if (ret) {
        // 작업경로 선택 사항 확인
        for (var idx = 0; idx < ds_odrCommWrkPath.getRowCount(); idx++) {
            if (parseInt(ds_odrCommWrkPath.getCellData(idx, "ctrtWrkPathSeq")) <= 0) {
                $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업경로"));
                return false;
            }
        }

        return true;
    } else {
        return false;
    }

}

