scwin.f_setWorkLobranNoDataAutoClose = async function (row, pCode, pName, pClose, pAllSearch, pDptWrkPlsYn, pOrgValueCheck, pNoDataCloseTF, pDptWrkChangeTF) {

    // 작업장 팝업 - 작업단계별 작업장 팝업
    pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim(); // 작업구분코드
    if ($c.gus.cfIsNull(pDptWrkChangeTF)) pDptWrkChangeTF = "F";

    // 조회조건이 아닌경우 종료
    if ($c.gus.cfIsNull(pCode) && $c.gus.cfIsNull(pName)) {
        return false;
    }

    pWhere = pWrkPlClsCd;

    udc_comCode1.setSelectId("retrieveWrkPlInfoNoDataAutoClose"); // XML상의 SELECT ID
    await udc_comCode1.cfCommonPopUp(scwin.udc_wrkPlInfoNoDataAutoClose_callBackFunc // 콜백 함수
        , pCode // 화면에서의 ??? Code Element의 Value
        , pName // 화면에서의 ??? Name Element의 Value
        , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
        , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
        , null // Title순서
        , null // 보여주는 각 컬럼들의 폭
        , null // 컬럼중에서 숨기는 컬럼 지정
        , pWhere // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
        , null // POP-UP뛰을때 원도우의 사용자 정의 폭
        , null // POP-UP뛰을때 우도우의 사용자 정의 높이
        , null // 윈도우 위치 Y좌표
        , null // 윈도우 위치 X좌표
        , null // 중복체크여부 ("F")
        , pAllSearch // 전체검색허용여부 ("F")
        , "작업장,작업장코드,작업장명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , pNoDataCloseTF // Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
        , null
    );
}

//-------------------------------------------------------------------------
// 작업단계 정보를 설정한다.
// - 작업경로별 조회된 오더작업단계, 계약작업단계 정보 중
//   오더작업단계 정보가 존재하는 경우 작업단계 그리드에 오더작업단계정보를 설정하고
//   오더작업단계 정보가 존재하지 않는경우 계약작업단계정보를 작업단계 그리드에 설정한다. 
//-------------------------------------------------------------------------
scwin.f_setWorkPathStepDetail = async function () {
    if (ds_lobran.getRowCount() > 0) {
        ds_lobran.setRowPosition(0);
    }

    // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
    if (scwin.userId == "040239") {
        scwin.internalSellLodeptCd = "4A5";
        scwin.internalSellLodeptNm = "인천제강운송";
    } else {
        scwin.internalSellLodeptCd = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranCd"); // 운송부서코드
        scwin.internalSellLodeptNm = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranNm"); // 운송부서명
    }
    scwin.wrkLobranCdRow = 0; // 작업점소 설정 ROW 초기화

debugger;

    //if (ds_odrWrkPathStep.getRowCount() > 0 && ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtWrkPathSeq") == ds_odrCommWrkPath.getOriginalCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtWrkPathSeq")) {
    // 1. 현재 선택된 행의 인덱스를 가져옵니다.
    let rowIdx = ds_odrCommWrkPath.getRowPosition(); 

    console.log("ds_odrWrkPathStep.getRowCount()::",ds_odrWrkPathStep.getRowCount());
    console.log("ds_odrCommWrkPath.getCellData:getCellData:",ds_odrCommWrkPath.getCellData(rowIdx, "ctrtWrkPathSeq"));
    console.log("ds_odrWrkPathStep.getRowCount():getOriginalCellData:",ds_odrCommWrkPath.getOriginalCellData(rowIdx, "ctrtWrkPathSeq"));

    // 2. 조건문 처리
    if (ds_odrWrkPathStep.getRowCount() > 0 && 
        ds_odrCommWrkPath.getCellData(rowIdx, "ctrtWrkPathSeq") == ds_odrCommWrkPath.getOriginalCellData(rowIdx, "ctrtWrkPathSeq")) {

        // 조건이 참일 때 실행할 로직
        console.log("하위 데이터가 존재하고, 현재 행의 순번이 변경되지 않은 상태입니다.");

        scwin.f_setOdrWrkPathStepToWrkPathStepDetail();

        $c.gus.cfEnableObjects([btn_orderWrkStepDetail, btn_dcSc]);

    } else if (ds_ctrtWrkPathStep.getRowCount() > 0) {
        scwin.f_setCtrtWrkPathStepToWrkPathStepDetail();

    } else {
        // 작업단계정보 (오더작업단계/계약작업단계)가 존재하지 않습니다.
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    scwin.ds_odrWrkPathStepDetail_OnFilter();
    ds_odrWrkPathStepDetail.reform();
    gr_odrWrkPathStpDetail.setFocusedCell(0, "odrWrkStpSeq", true); //edit : true

    // 버튼 활성화
    // $c.gus.cfEnableBtnOnly([btn_insertRow, btn_deleteRow, btn_undoMark]);

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(ds_odrWrkPathStepDetail.getRowPosition());
}

//-------------------------------------------------------------------------
// 오더작업단계정보를 작업단계 그리드에 설정한다.
//-------------------------------------------------------------------------
scwin.f_setOdrWrkPathStepToWrkPathStepDetail = function () {
    //참고
    let totCnt = ds_odrWrkPathStep.getRowCount();
    //ds_odrWrkPathStepDetail.ImportData(ds_odrWrkPathStep.ExportData(1, ds_odrWrkPathStep.CountRow, true));
    ds_odrWrkPathStepDetail.setJSON(ds_odrWrkPathStep.getRangeJSON(0, totCnt - 1));

    for (var i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        // [중요] ASIS : ImportData는 컬럼 순서대로 복사하기 때문에 TOBE에서는 setJSON 후에 아래 컬럼에 대해 다시 SET
        ds_odrWrkPathStepDetail.setCellData(i, "odrWrkPathNm", ds_odrWrkPathStep.getCellData(i, "ctrtWrkPathNm"));

        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim())) { // 작업구분이 운송인 경우 작업장 표시 안함.
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNmOrg", "");
        }

        if (ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") == SdConstants.SELPCH_ITEM_CD_NOSELL) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCdOrg", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNmOrg", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNmOrg", "");
        }
    }

}

//-------------------------------------------------------------------------
// 계약작업단계정보를 작업단계 그리드에 설정한다.
//-------------------------------------------------------------------------
scwin.f_setCtrtWrkPathStepToWrkPathStepDetail = function () {
    var v_wrkStDtm = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "wrkStDt") + " " + ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "wrkStHh");
    var workStartDate = v_wrkStDtm.toDate("YYYYMMDD HHmm");
    var v_wrkEndDtm = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "wrkEndDt") + " " + ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "wrkEndHh");
    var workEndDate = v_wrkEndDtm.toDate("YYYYMMDD HHmm");
    var nextWorkEndDate = new Date();
    var newRow = 0;
    for (var i = 0; i < ds_ctrtWrkPathStep.getRowCount(); i++) {
        nextWorkEndDate = workStartDate.after(0, 0, 0, 0, i * 20); // 품명 작업시작 시간에 20분씩 증가시켜 작업단계별 시작시간에 설정한다.

        newRow = ds_odrWrkPathStepDetail.insertRow();
        ds_odrWrkPathStepDetail.setRowPosition(newRow);
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrNo", ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "odrNo")); // 오더번호
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "commSeq", ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "commSeq")); // 품명순번       
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkPathSeq", ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "odrWrkPathSeq")); // 오더작업경로순번
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtWrkPathSeq")); // 계약작업경로순번
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkPathNm", ds_ctrtWrkPathStep.getCellData(i, "ctrtWrkPathNm")); // 작업경로명
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq", ds_ctrtWrkPathStep.getCellData(i, "ctrtWrkStpSeq")); // 오더작업단계순번
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd", ds_ctrtWrkPathStep.getCellData(i, "wrkPlClsCd")); // 작업장구분코드        
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "bizDomCd", ds_ctrtWrkPathStep.getCellData(i, "bizDomCd")); // 사업영역코드
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd", ds_ctrtWrkPathStep.getCellData(i, "wrkStpCd")); // 작업단계코드
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpNm", ds_ctrtWrkPathStep.getCellData(i, "wrkStpNm")); // 작업단계명
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "selpchItemCd", ds_ctrtWrkPathStep.getCellData(i, "selpchItemCd")); // 매출입항목코드
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "selpchItemNm", ds_ctrtWrkPathStep.getCellData(i, "selpchItemNm")); // 매출입항목명

        if (i == 0) {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStDt", workStartDate.format("YYYYMMDD")); // 작업시작일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStHh", workStartDate.format("HHmm")); // 작업시작시간
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndDt", nextWorkEndDate.format("YYYYMMDD")); // 작업종료일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndHh", nextWorkEndDate.format("HHmm")); // 작업종료시간
        } else if (i > 0 && i < ds_ctrtWrkPathStep.getRowCount()) {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStDt", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "wrkEndDt")); // 작업시작일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStHh", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "wrkEndHh")); // 작업시작시간
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndDt", nextWorkEndDate.format("YYYYMMDD")); // 작업종료일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndHh", nextWorkEndDate.format("HHmm")); // 작업종료시간
        } else {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStDt", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "wrkEndDt")); // 작업시작일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStHh", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "wrkEndHh")); // 작업시작시간
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndDt", workEndDate.format("YYYYMMDD")); // 작업종료일자
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkEndHh", workEndDate.format("HHmm")); // 작업종료시간
        }

        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "vsslCd", ds_ctrtWrkPathStep.getCellData(i, "vsslCd")); // 선박코드
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "vsslNm", ds_ctrtWrkPathStep.getCellData(i, "vsslNm")); // 선박명
        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "portcnt", ds_ctrtWrkPathStep.getCellData(i, "portcnt")); // 항차       
    }

    ds_odrWrkPathStepDetail.reform();

    // 작업단계 정보를 완성한다.
    for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {

        if (j > 1 && j < ds_odrWrkPathStepDetail.getRowCount()) {
            // 이전 작업단계와 비교 하여 작업장/작업점소 정보를 설정한다.
            if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkPlClsCd").trim()) {

                // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                if (ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd") == "") {
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd")); // 출발작업장코드
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlNm")); // 출발작업장명
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNmOrg", ds_odrWrkPathStepDetail.getCellData(j - 1, "dtpWrkPlNm")); // 출발작업장명
                }
            } else if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim())) {

                // 작업장구분이 운송인 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd")); // 출발작업장코드              
            }

            // 다음 작업단계와 비교 하여 작업장/작업점소 정보를 설정한다.
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim())) {

                // 작업장구분이 운송인 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd")); // 도착작업장코드 <- 다음단계 출발작업장코드               
            } else if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkPlClsCd").trim()) {

                // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                if (ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd") == "") {
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd")); // 출발작업장코드
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlNm")); // 출발작업장명
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNmOrg", ds_odrWrkPathStepDetail.getCellData(j + 1, "dtpWrkPlNm")); // 출발작업장명
                }

                // 이전 작업장단계가 운송단계인 경우 출발지를 도착지로 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkPlClsCd").trim())) {
                    if (ds_odrWrkPathStepDetail.getCellData(j - 1, "arvWrkPlCd") == "") {
                        ds_odrWrkPathStepDetail.setCellData(j - 1, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd")); // 출발작업장코드
                    }
                }
            }

        }
    }

    // 출발지 도착지 정보를 설정한다.
    scwin.f_setOdrWrkPathStepDptArv();

    // 작업 단계 정보 재설정
    scwin.f_setWorkStepInfoRefresh();
}

//-------------------------------------------------------------------------
// 저장하기전 선택하지 않은 작업단계 정보를 삭제한다.
// 저장하기전 수정되지 않은 작업경로의 작업단계가 수정되지 않은 경우  삭제하여 전송하지 않는다.
//-------------------------------------------------------------------------
scwin.f_chkOdrWrkPathStep = function () {
    scwin.hid_chkUseFilter = false;
    scwin.ds_odrWrkPathStepDetail_OnFilter();

    //var v_maxOdrWrkPathSeq = ds_odrCommWrkPath.Max(ds_odrCommWrkPath.ColumnIndex("odrWrkPathSeq"), 0, ds_odrCommWrkPath.CountRow);  // 오더작업경로순번 최대값
    var colData = ds_odrCommWrkPath.getColData("odrWrkPathSeq"); // 해당 colum의 데이터를 배열로 반환
    var v_maxOdrWrkPathSeq = Math.max.apply(null, colData);      // colData배열에서 최대값을 반환

    // 품명별 작업경로 정보
    for (var i = 0; i < ds_odrCommWrkPath.getRowCount(); i++) {
        // 오더 작업경로 정보
        var v_odrNo = ds_odrCommWrkPath.getCellData(i, "odrNo"); // 오더번호
        var v_commSeq = ds_odrCommWrkPath.getCellData(i, "commSeq"); // 오더 품명 순번
        var v_odrWrkPathSeq = ds_odrCommWrkPath.getCellData(i, "odrWrkPathSeq"); // 오더작업경로순번
        var v_ctrtWrkPathSeq = ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq"); // 계약작업경로순번

        if (ds_odrCommWrkPath.getCellData(i, "odrWrkPathSeq") <= 0) {
            ds_StockInfo.modifyRowStatus(i, "C"); // INSERT로 설정 : 오더작업경로 정보가 존재하지 않는 경우
            v_maxOdrWrkPathSeq++;
        }

        for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
            if (v_odrNo == ds_odrWrkPathStepDetail.getCellData(j, "odrNo") && v_commSeq == ds_odrWrkPathStepDetail.getCellData(j, "commSeq")) {
                // 저장하기전 선택하지 않은 작업단계 정보를 삭제한다.
                if (v_odrWrkPathSeq != ds_odrWrkPathStepDetail.getCellData(j, "odrWrkPathSeq") || v_ctrtWrkPathSeq != ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq")) {
                    ds_odrWrkPathStepDetail.removeRow(j); // 테스트 필요함!!!!!!!
                    j--;
                }

                // 저장하기전 수정되지 않은 작업경로의 작업단계가 수정되지 않은 경우 삭제하여 전송하지 않는다.
                if (!$c.gus.cfIsNull(ds_odrCommWrkPath.getCellData(i, "wrkRsltsNo"))) {

                    if (ds_odrCommWrkPath.getCellData(i, "odrNo") == ds_odrWrkPathStepDetail.getCellData(j, "odrNo")
                        && ds_odrCommWrkPath.getCellData(i, "commSeq") == ds_odrWrkPathStepDetail.getCellData(j, "commSeq")
                        && ds_odrCommWrkPath.getCellData(i, "odrWrkPathSeq") == ds_odrWrkPathStepDetail.getCellData(j, "odrWrkPathSeq")) {
                        ds_odrWrkPathStepDetail.removeRow(j);
                        j--;
                    }
                }

                if (v_odrWrkPathSeq == 0) {
                    ds_odrWrkPathStepDetail.setCellData(j, "odrWrkPathSeq", v_maxOdrWrkPathSeq);
                }
            }
        }

        if (v_odrWrkPathSeq == 0) {
            ds_odrCommWrkPath.setCellData(i, "odrWrkPathSeq", v_maxOdrWrkPathSeq);
        }
    }

    scwin.hid_chkUseFilter = true;
    scwin.ds_odrWrkPathStepDetail_OnFilter();
};

//-------------------------------------------------------------------------
// 작업일시 베분조회 및 수정화면으로 이동한다.
//-------------------------------------------------------------------------
scwin.f_orderWrkStepDetail = function () {
    let row = ds_odrWrkPathStepDetail.getRowPosition();
    let strOrderDetailUrl = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_14b.xml";
    let strPgmId = "sd_402_01_14b.jsp";

    if (parseInt(row) >= 0) {
        // 선택된 오더 정보 : 오더번호
        let v_odrNo = ds_order.getCellData(0, "odrNo");

        let paramObj = {
            odrNo: v_odrNo,
            type: "retrieve"
        };

        $p.parent().scwin.f_TabMenuUpdate(strOrderDetailUrl, strPgmId, "작업일시배분조회및수정", paramObj);
    } else {
        cfAlertMsg(MSG_CM_ERR_056, new Array("작업단계"));
        return;
    }
}

//-------------------------------------------------------------------------
// 해당품명의 실적 발생여부를 확인
//-------------------------------------------------------------------------
scwin.f_chkResultsConfirmationCommodity = function (row) {
    if (!$c.gus.cfIsNull(ds_odrCommWrkPath.getCellData(row, "wrkRsltsNo").trim())) {
        return true; // 실적이 존재하는 경우
    }

    return false; // 실적이 존재하지 않는 경우
}

//-------------------------------------------------------------------------
// 작업단계 출도착지 정보를 설정한다.
// - 처리 규칙 
//    1. 선택된 작업 경로의 계약작업단계를 순차적으로 검색하여 출발작업장구분과 동일한 작업장구분의 첫번째 작업장에 출발 작업장 정보를 설정
//    2. 선택된 작업 경로의 계약작업단계를 역순으로 검색하여 도착작업장구분과 동일한 작업장구분의 첫번째 작업장에 도착 작업장 정보를 설정
//    3. 출발작업장과 도착 작업장이 동일한 경우 도착작업장을 설정하지 않는다.
//    4. 출발작업장과 도착작업장 정보가 없는 경우 설정하지 않는다.
//    5. 작업장구분코드가 D, G 인 경우는 동일한 경우로 인식한다. 
//-------------------------------------------------------------------------
scwin.f_setOdrWrkPathStepDptArv = async function () {

    var v_dptRow = 0;
    var v_impExpDomesticClsCd = ds_order.getCellData(ds_order.getRowPosition(), "impExpDomesticClsCd"); // 수출입내수구분코드 - IMP_EXP_DOMESTIC_CLS_CD

    var v_dptWrkPlCd = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "dptWrkPlCd"); // 출발 작업장코드
    var v_dptWrkPlNm = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "dptWrkPlNm"); // 출발 작업장명
    var v_dptWrkPlClsCd = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "dptWrkPlClsCd"); // 출발 작업장 구분코드

    var v_arvWrkPlCd = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "arvWrkPlCd"); // 도착 작업장코드
    var v_arvWrkPlNm = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "arvWrkPlNm"); // 도착 작업장명
    var v_arvWrkPlClsCd = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "arvWrkPlClsCd"); // 도착 작업장 구분코드

    if (v_impExpDomesticClsCd == DsConstants.IMP_CD) {
        // 수입인 경우

        // 작업단계 정보를 완성한다. - 도착지 정보 설정
        for (var j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {

            // 도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다.
            if (v_dptRow >= 0 && v_dptRow >= j) {
                $c.gus.cfAlertMsg("도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다."); // 도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다.
                break;
            }

            // 도착 작업장 설정
            if (!$c.gus.cfIsNull(v_arvWrkPlCd)) {

                if (v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_DOOR || v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RGN) {
                    // 작업장 구분이 Door(D), 지역(G) 인경우
                    if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_RGN || ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_DOOR) {

                        // 수입인 경우 이미 설정된 정보를 도착지 정보로 대체한다.
                        // 도착작업장 구분코드와 작업단계구분코드가 같은 경우 해당 단계의 작업장정보에 도착 작업장 정보를 설정
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", v_arvWrkPlCd); // 작업장코드 <- 도착작업장코드
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", v_arvWrkPlNm); // 작업장명 < - 도착작업장명

                        var pCode = ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd");

                        // 작업장 설정
                        scwin.ds_odrWrkPathStepDetail_row = j; // 콜백함수 사용해야해서 작업단계 콜백 ROW SET
                        await scwin.f_setWorkLobranNoDataAutoClose(j, pCode, '', 'T', 'F', 'T', 'F', 'T');

                        // 작업장구분코드가 운송인 경우 작업장명을 보여주지 않는다.
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim())) {
                            ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", "");
                        }

                        break;
                    }
                } else if (v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_PIER || v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_BERTH) {
                    // 작업장 구분이 선석(B), 부두(P) 인경우
                    if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_PIER || ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_BERTH) {

                        // 수입인 경우 이미 설정된 정보를 도착지 정보로 대체한다.

                        // 도착작업장 구분코드와 작업단계구분코드가 같은 경우 해당 단계의 작업장정보에 도착 작업장 정보를 설정
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", v_arvWrkPlCd); // 작업장코드 <- 도착작업장코드
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", v_arvWrkPlNm); // 작업장명 < - 도착작업장명

                        var pCode = ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd");

                        // 작업장 설정
                        scwin.ds_odrWrkPathStepDetail_row = j; // 콜백함수 사용해야해서 작업단계 콜백 ROW SET
                        await scwin.f_setWorkLobranNoDataAutoClose(j, pCode, '', 'T', 'F', 'T', 'F', 'T');

                        // 작업장구분코드가 운송인 경우 작업장명을 보여주지 않는다.
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim())) {
