    if (ds_order.getRowCount() > 0 && ds_odrCommWrkPath.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.ds_ctrtWrkPath_OnLoadCompleted = function () {
    if (ds_order.getRowCount() > 0 && ds_ctrtWrkPath.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
}

